form:Form.form:Scripts:
		
function RegDelete()
{
  if (Ctrl("DELETE")?false:true) return false;
  if (!Ctrl("DELETE").GetEnabled()) return false;            

 	var rolVal;  
 	var nSQL = GetProxy().SQLService();
 	rolVal = nSQL.GetXML(Ctrl("main").getResource("QRY_ROL_USOWF"), "<PARAM oi_organigrama=\""+Ctrl("PARENT").GetXValue()+"\" oi_role=\""+Ctrl("LIST").GetSelectAttrValue("id")+"\"/>");    

 	if(rolVal.GetAttr("flag") != "1") 
 	{	
		if (!confirm("¿Esta seguro que quiere eliminar el Registro?")) return false;	
  		Ctrl("main").DoEvent("DELETE");
  		return true;
	}
	else
	{
		alert("No puede eliminar el Actor, ya que está siendo utilizado dentro de un nodo de un WF que utiliza éste ORG");
		return false;
	} 
}
